script.js:
var container = document.getElementById("container");
var roseQuoteHolder = document.getElementById("roseQuotes");

roseQuoteHolder.style.opacity = 0;
function rose(index) {
	// random rose quote
	roseQuoteHolder.style.opacity = 1;
	var mouseX = event.clientX;
	var mouseY = event.clientY;

	var random = Math.floor(Math.random() * 10);
	console.log("clicked", mouseX, mouseY);

	roseQuoteHolder.innerHTML = roseQuotes[random] + "<br/>-Rose Nylund";
	roseQuoteHolder.style.top = mouseY + "px";
	roseQuoteHolder.style.left = mouseX + "px";
}

var roseQuotes = [
	"You know what they say: You can lead a herring to water, but you have to walk really fast or else he'll die!",
	"Oh, blow it out your tubenburbles!",
	"I thought you wore too much makeup and were a slut. I was wrong. You don’t wear too much makeup.",
	"Like we say in St. Olaf, Christmas without fruitcake is like St. Sigmund's Day without the headless boy.",
	"Sometimes life just isn’t fair, kiddo.",
	"Norwegians are notoriously bad at Spanish.",
	"Boy, if I wasn't going, I'd really be jealous of me.",
	"I don't understand how a thermos keeps things both hot and cold.",
	"If you hold a bird gently, the bird will stay. But if you squeeze the bird, his eyes will bug out.",
	"The older you get the better you get. Unless you’re a banana."
];

style.css:
* {
	margin: 0;
	padding: 0;
	box-sizing: border-box;
}
#roseQuotes {
position:absolute;
	font-size: .8rem;
	text-transform:uppercase;
	letter-spacing:2px;
	width:200px;
	height:150px;
	background-color:white;
	padding:5px;
	z-index:9999999999999;
	display:flex;
		justify-content:center;
		vertical-align:middle;
	align-items:center;
	align-content:center;
	padding:10px;
	border-radius:10px;


}
body,
html {
	height: 100%;
	width: 100%;
	font-family: sans-serif;
	overflow: hidden;
}
.container:after {
	content:'';
	position:absolute;
	width:100vw;
	height:100vh;
		background-image:url('https://media-cldnry.s-nbcnews.com/image/upload/t_fit-1500w,f_auto,q_auto:best/rockcms/2021-12/betty-white-golden-girls-rose-te-main-211229-be1685.jpg');
	background-size:cover;
	opacity:.05;
}
.container {
	position: relative; 
	width: 100vw;
	height: 100vh; 

}
.marker {
	width:50px; height: 50px;
	background-color:black;
	border-radius:100%;
	position:absolute;
	text-transform:uppercase;
	letter-spacing:1px;
	z-index:999999999;
	transition:all .15s;
}

.blanche {
		top:75%; left:75%;
}
.dorothy {
		top:25%; left:25%;
}

.sophia {
		top:calc(50% + -25px); left:calc(50% - 25px);
}
.marker:after {
		content:' ';
	position:relative;
	display:flex;
		justify-content:center;
		vertical-align:middle;
	align-items:center;
	align-content:center;
	height:50px;

}
.marker.blanche:hover:after  {
	content: 'Blanche Devereaux';
}
.marker.dorothy:hover:after {
